'use client';

import { useScroll, useReducedMotion, useTransform, motion } from 'framer-motion';
import { useState, useEffect, useCallback } from 'react';
import {
  SiteHeader,
  SiteFooter,
  EnhancedHeroSection,
  EnhancedAboutSection,
  EnhancedWorkSection,
  EnhancedBookSection,
  EnhancedWritingSection,
  EnhancedContactSection,
  CertificationsSection,
} from '@/components/site';
import { CommandPalette, CommandKTrigger, SplashOverlay } from '@/components/effects';
import { useTheme } from '@/lib/theme';

export default function Home() {
  const { scrollYProgress } = useScroll();
  const [isCommandOpen, setIsCommandOpen] = useState(false);
  const [showSplash, setShowSplash] = useState(true);
  const prefersReducedMotion = useReducedMotion();
  const { isDark, toggle } = useTheme();

  // Fixed scroll progress using useTransform
  const scaleX = useTransform(scrollYProgress, [0, 1], [0, 1]);

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'k' && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        setIsCommandOpen(prev => !prev);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handleNavigate = useCallback((href: string) => {
    const element = document.querySelector(href);
    if (element) {
      element.scrollIntoView({ behavior: prefersReducedMotion ? 'auto' : 'smooth' });
    }
  }, [prefersReducedMotion]);

  return (
    <>
      {/* Splash Screen Entrance Overlay */}
      {showSplash && (
        <SplashOverlay onComplete={() => setShowSplash(false)} />
      )}

      {/* Scroll Progress Indicator - Fixed hydration with motion.div */}
      <motion.div
        className="scroll-progress"
        style={{ 
          scaleX,
          backgroundColor: isDark ? '#fafafa' : '#171717'
        }}
      />

      {/* Header */}
      <SiteHeader />

      {/* Main Content */}
      <main id="main-content" className="flex-1">
        {/* Hero Section */}
        <EnhancedHeroSection />

        {/* ASCII Divider */}
        <div className="editorial-container">
          <div className="flex items-center justify-center gap-4 py-8">
            <span className="font-mono text-muted-foreground/20 text-xl">{'тХР'.repeat(20)}</span>
            <span className="font-mono text-muted-foreground/30">тЧИ</span>
            <span className="font-mono text-muted-foreground/20 text-xl">{'тХР'.repeat(20)}</span>
          </div>
        </div>

        {/* About Section */}
        <EnhancedAboutSection />

        {/* Work Section */}
        <EnhancedWorkSection />

        {/* Book Section */}
        <EnhancedBookSection />

        {/* Writing Section */}
        <EnhancedWritingSection />

        {/* Certifications Section */}
        <CertificationsSection />

        {/* Contact Section */}
        <EnhancedContactSection />
      </main>

      {/* Footer */}
      <SiteFooter />

      {/* Command Palette */}
      <CommandPalette
        isOpen={isCommandOpen}
        onClose={() => setIsCommandOpen(false)}
        onNavigate={handleNavigate}
        isDark={isDark}
        onToggleTheme={toggle}
      />

      {/* Command K Trigger */}
      <CommandKTrigger onClick={() => setIsCommandOpen(true)} />
    </>
  );
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { motion, AnimatePresence } from 'framer-motion';
import { Moon, Sun, Menu, X } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import { useTheme } from '@/lib/theme';

const navLinks = [
  { href: '#about', label: 'About' },
  { href: '#work', label: 'Work' },
  { href: '#writing', label: 'Writing' },
  { href: '#book', label: 'Book' },
  { href: '#contact', label: 'Contact' },
];

export function SiteHeader() {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const { isDark, toggle } = useTheme();

  // Handle scroll
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Handle scroll
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);



  return (
    <header
      className={cn(
        'fixed top-0 left-0 right-0 z-50 transition-all duration-300',
        isScrolled 
          ? 'bg-background/80 backdrop-blur-md border-b border-border' 
          : 'bg-transparent'
      )}
    >
      <nav className="editorial-container">
        <div className="flex items-center justify-between h-16 md:h-20">
          {/* Logo */}
          <Link 
            href="/" 
            className="group flex items-center gap-2"
          >
            <span className="font-mono text-xs text-muted-foreground group-hover:text-foreground transition-colors">
              {'//'}
            </span>
            <span className="font-semibold tracking-tight">
              Douglas Mitchell
            </span>
          </Link>

          {/* Desktop Navigation */}
          <div className="hidden md:flex items-center gap-1">
            {navLinks.map((link) => (
              <a
                key={link.href}
                href={link.href}
                className="nav-link"
              >
                {link.label}
              </a>
            ))}
          </div>

          {/* Actions */}
          <div className="flex items-center gap-2">
            {/* Theme Toggle */}
            <Button
              variant="ghost"
              size="icon"
              onClick={toggle}
              className="h-9 w-9"
              aria-label={isDark ? 'Switch to light mode' : 'Switch to dark mode'}
            >
              <motion.div
                initial={false}
                animate={{ rotate: isDark ? 180 : 0 }}
                transition={{ duration: 0.3 }}
              >
                {isDark ? (
                  <Sun className="h-4 w-4" />
                ) : (
                  <Moon className="h-4 w-4" />
                )}
              </motion.div>
            </Button>

            {/* Mobile Menu Toggle */}
            <Button
              variant="ghost"
              size="icon"
              className="md:hidden h-9 w-9"
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              aria-label="Toggle menu"
            >
              {isMobileMenuOpen ? (
                <X className="h-4 w-4" />
              ) : (
                <Menu className="h-4 w-4" />
              )}
            </Button>

            {/* CTA - Desktop */}
            <a
              href="#contact"
              className="hidden md:inline-flex cta-button text-sm"
            >
              Let's Connect
            </a>
          </div>
        </div>
      </nav>

      {/* Mobile Menu */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.2 }}
            className="md:hidden bg-background border-b border-border"
          >
            <div className="editorial-container py-4 space-y-1">
              {navLinks.map((link) => (
                <a
                  key={link.href}
                  href={link.href}
                  onClick={() => setIsMobileMenuOpen(false)}
                  className="block py-2 text-foreground hover:text-primary transition-colors"
                >
                  {link.label}
                </a>
              ))}
              <a
                href="#contact"
                onClick={() => setIsMobileMenuOpen(false)}
                className="block py-2 text-primary font-medium"
              >
                Let's Connect тЖТ
              </a>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </header>
  );
}

@import "tailwindcss";
@import "tw-animate-css";

@custom-variant dark (&:is(.dark *));

/* тХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХР
   DOUGLAS MITCHELL - ARCHITECTURAL EDITORIAL DESIGN SYSTEM
   ASCII-INFLECTED VISUAL LANGUAGE
   тХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХР */

@theme inline {
  /* Color System */
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);

  /* Sidebar colors */
  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);

  /* Chart colors */
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);

  /* Base colors */
  --color-ring: var(--ring);
  --color-input: var(--input);
  --color-border: var(--border);
  --color-destructive: var(--destructive);
  --color-accent-foreground: var(--accent-foreground);
  --color-accent: var(--accent);
  --color-muted-foreground: var(--muted-foreground);
  --color-muted: var(--muted);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);

  /* Radius */
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
}

/* тХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХР
   LIGHT MODE - Architectural Bright Premium
   тХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХР */
:root {
  /* Core Design Tokens */
  --radius: 0.5rem;

  /* Architectural Light Theme */
  --background: oklch(0.99 0.002 90);
  --foreground: oklch(0.15 0.01 250);

  --card: oklch(1 0 0);
  --card-foreground: oklch(0.15 0.01 250);

  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.15 0.01 250);

  --primary: oklch(0.20 0.02 250);
  --primary-foreground: oklch(0.98 0.005 90);

  --secondary: oklch(0.96 0.005 250);
  --secondary-foreground: oklch(0.20 0.02 250);

  --muted: oklch(0.97 0.003 250);
  --muted-foreground: oklch(0.50 0.01 250);

  --accent: oklch(0.95 0.01 250);
  --accent-foreground: oklch(0.20 0.02 250);

  --destructive: oklch(0.55 0.22 25);

  --border: oklch(0.92 0.005 250);
  --input: oklch(0.92 0.005 250);
  --ring: oklch(0.60 0.02 250);

  /* Chart Colors - Warm Neutral */
  --chart-1: oklch(0.55 0.15 35);
  --chart-2: oklch(0.55 0.12 180);
  --chart-3: oklch(0.45 0.08 250);
  --chart-4: oklch(0.70 0.15 85);
  --chart-5: oklch(0.65 0.18 70);

  /* Sidebar */
  --sidebar: oklch(0.98 0.002 90);
  --sidebar-foreground: oklch(0.15 0.01 250);
  --sidebar-primary: oklch(0.20 0.02 250);
  --sidebar-primary-foreground: oklch(0.98 0.005 90);
  --sidebar-accent: oklch(0.95 0.01 250);
  --sidebar-accent-foreground: oklch(0.20 0.02 250);
  --sidebar-border: oklch(0.92 0.005 250);
  --sidebar-ring: oklch(0.60 0.02 250);

  /* ASCII Design Tokens */
  --ascii-border: oklch(0.85 0.01 250);
  --ascii-text: oklch(0.40 0.01 250);
  --ascii-accent: oklch(0.30 0.02 250);

  /* Editorial Spacing */
  --editorial-gap: clamp(1.5rem, 4vw, 3rem);
  --section-gap: clamp(3rem, 8vw, 6rem);
}

/* тХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХР
   DARK MODE - Cinematic Depth
   тХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХР */
.dark {
  --background: oklch(0.12 0.01 250);
  --foreground: oklch(0.95 0.005 90);

  --card: oklch(0.16 0.01 250);
  --card-foreground: oklch(0.95 0.005 90);

  --popover: oklch(0.16 0.01 250);
  --popover-foreground: oklch(0.95 0.005 90);

  --primary: oklch(0.92 0.01 250);
  --primary-foreground: oklch(0.12 0.01 250);

  --secondary: oklch(0.22 0.01 250);
  --secondary-foreground: oklch(0.95 0.005 90);

  --muted: oklch(0.20 0.01 250);
  --muted-foreground: oklch(0.65 0.01 250);

  --accent: oklch(0.22 0.01 250);
  --accent-foreground: oklch(0.95 0.005 90);

  --destructive: oklch(0.65 0.20 22);

  --border: oklch(0.25 0.01 250);
  --input: oklch(0.22 0.01 250);
  --ring: oklch(0.55 0.02 250);

  /* Chart Colors - Deep */
  --chart-1: oklch(0.65 0.18 35);
  --chart-2: oklch(0.60 0.15 180);
  --chart-3: oklch(0.55 0.10 250);
  --chart-4: oklch(0.70 0.18 85);
  --chart-5: oklch(0.65 0.20 70);

  /* Sidebar */
  --sidebar: oklch(0.14 0.01 250);
  --sidebar-foreground: oklch(0.95 0.005 90);
  --sidebar-primary: oklch(0.92 0.01 250);
  --sidebar-primary-foreground: oklch(0.12 0.01 250);
  --sidebar-accent: oklch(0.22 0.01 250);
  --sidebar-accent-foreground: oklch(0.95 0.005 90);
  --sidebar-border: oklch(0.25 0.01 250);
  --sidebar-ring: oklch(0.55 0.02 250);

  /* ASCII Design Tokens - Dark */
  --ascii-border: oklch(0.30 0.01 250);
  --ascii-text: oklch(0.60 0.01 250);
  --ascii-accent: oklch(0.75 0.02 250);
}

/* тХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХР
   BASE LAYER
   тХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХР */
@layer base {
  * {
    @apply border-border outline-ring/50;
  }

  body {
    @apply bg-background text-foreground;
    font-feature-settings: "rlig" 1, "calt" 1;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  /* Smooth scroll with reduced motion support */
  html {
    scroll-behavior: smooth;
  }

  @media (prefers-reduced-motion: reduce) {
    html {
      scroll-behavior: auto;
    }

    *,
    *::before,
    *::after {
      animation-duration: 0.01ms !important;
      animation-iteration-count: 1 !important;
      transition-duration: 0.01ms !important;
      scroll-behavior: auto !important;
    }
  }
}

