/* ASCII Border System */
.ascii-border {
  border: 1px solid var(--ascii-border);
  position: relative;
}

.ascii-border::before {
  content: '+';
  position: absolute;
  top: -0.5rem;
  left: -0.5rem;
  font-family: var(--font-mono);
  font-size: 0.75rem;
  color: var(--ascii-text);
  background: var(--background);
  padding: 0 0.25rem;
}

/* ASCII Grid Overlay */
.ascii-grid {
  background-image: 
    linear-gradient(var(--ascii-border) 1px, transparent 1px),
    linear-gradient(90deg, var(--ascii-border) 1px, transparent 1px);
  background-size: 20px 20px;
  background-position: -1px -1px;
}

/* ASCII Divider */
.ascii-divider {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-family: var(--font-mono);
  font-size: 0.75rem;
  color: var(--ascii-text);
  letter-spacing: 0.05em;
}

.ascii-divider::before,
.ascii-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--ascii-border);
}

/* ASCII Section Marker */
.ascii-marker {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  font-family: var(--font-mono);
  font-size: 0.625rem;
  text-transform: uppercase;
  letter-spacing: 0.2em;
  color: var(--muted-foreground);
}

.ascii-marker::before {
  content: '[';
  color: var(--ascii-accent);
}

.ascii-marker::after {
  content: ']';
  color: var(--ascii-accent);
}

/* Evidence Grid */
.evidence-grid {
  display: grid;
  gap: 1px;
  background: var(--ascii-border);
  border: 1px solid var(--ascii-border);
}

.evidence-grid > * {
  background: var(--background);
  padding: 1rem;
}

/* Typewriter Effect */
@keyframes typewriter {
  from { width: 0; }
  to { width: 100%; }
}

@keyframes blink {
  50% { border-color: transparent; }
}

.typewriter {
  overflow: hidden;
